    'glossary.ccs.short': 'Den dominerende DC-hurtigladesstandarden i Europa og Nord-Amerika.',
    'glossary.ccs.def': 'CCS kombinerer AC- og DC-pinner i én kontakt. CCS1 (Nord-Amerika), CCS2 (Europa). Opptil ~350 kW. Windrose støtter begge varianter.',
    'glossary.mcs.abbr': 'Megawatt-ladesystem',
    'glossary.mcs.short': 'Neste generasjons lading for tunge lastebiler — opptil 3,75 MW.',
