    'glossary.plugcharge.abbr': 'ISO 15118',
    'glossary.plugcharge.short': 'Plugg inn og ladingen starter — ingen kort, app eller PIN.',
    'glossary.plugcharge.def': 'Automatisk identifikasjon og fakturering mellom kjøretøy og lader. Plug&Charge på 1M+ ladepunkter i 70+ land.',
