    'glossary.ccs.short': 'Den dominerande DC-snabbladdningsstandarden i Europa och Nordamerika.',
    'glossary.ccs.def': 'CCS kombinerar AC- och DC-pinnar i ett uttag. CCS1 (Nordamerika), CCS2 (Europa). Upp till ~350 kW. Windrose stöder båda.',
    'glossary.mcs.abbr': 'Megawatt-ladesystem',
    'glossary.mcs.short': 'Nästa generations laddning för tunga lastbilar — upp till 3,75 MW.',
    'glossary.mcs.def': 'Vid 1–3,75 MW når en Windrose-lastbil 80 % på ~30 minuter — jämförbart med ett dieselstopp.',
    'glossary.plugcharge.abbr': 'ISO 15118',
    'glossary.plugcharge.short': 'Plugga in och laddningen startar — inget kort, app eller PIN.',
    'glossary.plugcharge.def': 'Automatisk identifiering och fakturering mellan fordon och laddare. Plug&Charge på 1M+ laddpunkter i 70+ länder.',
    'glossary.cat.battery': 'Batteri',
    'glossary.lfp.abbr': 'Litiumjärnfosfat',
    'glossary.lfp.short': 'Batterikemins Windrose använder — säkrare, mer hållbar, klarar laddningscykler.',
    'glossary.lfp.def': 'LFP använder järn och fosfat istället för nickel, mangan och kobolt. Ingen termisk rusning, 3.000–5.000 cyklar, daglig 100 % laddning utan degradering.',
    'glossary.soc.abbr': 'Laddningstillstånd',
    'glossary.soc.short': 'Batteriets laddningsnivå i procent.',
    'glossary.soc.def': 'SOC är det elektriska motstycket till bränslemätaren. BMS övervakar i realtid och varnar under 20 %.',
    'glossary.cat.drivetrain': 'Drivlina',
    'glossary.epto.abbr': 'Elektriskt kraftuttag',
    'glossary.epto.short': 'Driver kylning, kranar och hydraulik direkt från batteriet.',
    'glossary.epto.def': 'ePTO eliminerar separat dieselgenerator. Tillgänglig från Generation 3.',
    'glossary.bdouble.term': 'B-double',
    'glossary.bdouble.short': 'Vägtåg med två tillhängare — Windroses konfiguration för maximal nyttolast.',
    'glossary.bdouble.def': 'Två semitrailers bakom en dragbil. Tillåtet i Australien, NZ och delar av Europa; över 44-tonsgränsen.',
    'glossary.cat.driverassist': 'Körhjälp',
    'glossary.adas.abbr': 'L2+ / L4',
    'glossary.adas.short': 'Automatiseringsnivåer — från motorvägsstöd till fullständig självkörning i definierad zon.',
    'glossary.adas.def': 'L2+: filhållning, adaptiv farthållare, nödbromsning. L4: full autonomi i definierat domän. Windrose levererar L2+ standard.',
