    'glossary.aeb.def': 'Radar och frontkamera spårar hinder. Standard på alla Windrose-lastbilar.',
    'glossary.avm.abbr': 'Runt-om-sikt-monitor',
    'glossary.avm.short': '270° fågelperspektiv för dockning och backning.',
    'glossary.avm.def': 'AVM sammanfogar kameraflöden till ett uppifrånperspektiv. 270° täckning eliminerar blindzonrisken vid lastbryggor.',
