    'footer.social.facebook.desc': 'Follow Windrose Electric on Facebook for updates, events, and community news.',
    'greenlane_charging.body.0': 'Windrose and Greenlane have partnered to offer new customers',
    'greenlane_charging.body.1': 'The partnership removes a key barrier to EV adoption for fleet operators, providing reliable charging infrastructure from day one.',
