    'glossary.ccs.abbr': 'Połączony system ładowania',
    'glossary.ccs.short': 'Dominujący standard szybkiego ładowania DC w Europie i Ameryce Północnej.',
    'glossary.ccs.def': 'CCS łączy piny AC i DC w jednym złączu. CCS1 (Ameryka Płn.), CCS2 (Europa). Do ~350 kW. Windrose obsługuje obie wersje.',
    'glossary.mcs.abbr': 'System ładowania megawatowego',
    'glossary.mcs.short': 'Ładowanie nowej generacji dla ciężkich pojazdów — do 3,75 MW.',
    'glossary.mcs.def': 'Przy 1–3,75 MW ciężarówka Windrose osiąga 80% naładowania w ok. 30 min. — jak tankowanie dieslem.',
    'glossary.plugcharge.abbr': 'ISO 15118',
    'glossary.plugcharge.short': 'Włóż wtyczkę i ładowanie się rozpoczyna — bez karty, aplikacji ani PIN.',
    'glossary.plugcharge.def': 'Automatyczna identyfikacja i rozliczenie między pojazdem a ładowarką. Plug&Charge na 1M+ punktów w 70+ krajach.',
    'glossary.cat.battery': 'Akumulator',
    'glossary.lfp.abbr': 'Litowo-żelazowo-fosforanowy',
    'glossary.lfp.short': 'Chemia akumulatora Windrose — bezpieczniejsza, trwalsza i odporna na cykle.',
    'glossary.lfp.def': 'LFP używa żelaza i fosforanów zamiast niklu, manganu i kobaltu. Brak termicznego przegrzania, 3.000–5.000 cykli, ładowanie do 100% bez degradacji.',
    'glossary.soc.abbr': 'Stan naładowania',
    'glossary.soc.short': 'Aktualny poziom naładowania akumulatora w procentach.',
    'glossary.soc.def': 'SOC to elektryczny odpowiednik wskaźnika paliwa. BMS monitoruje w czasie rzeczywistym i ostrzega poniżej 20%.',
    'glossary.cat.drivetrain': 'Napęd',
    'glossary.epto.abbr': 'Elektryczny odbiór mocy',
    'glossary.epto.short': 'Zasila chłodzenie, żurawie i hydraulikę bezpośrednio z akumulatora.',
    'glossary.epto.def': 'ePTO eliminuje oddzielny generator diesla. Dostępny od Generacji 3.',
    'glossary.bdouble.term': 'B-double',
    'glossary.bdouble.short': 'Pociąg drogowy z dwiema naczepami — konfiguracja maksymalnej ładowności Windrose.',
    'glossary.bdouble.def': 'Dwie naczepy za jednym ciągnikiem. Dozwolony w Australii, NZ i części Europy; powyżej 44-tonowego limitu.',
    'glossary.cat.driverassist': 'Wspomaganie kierowcy',
    'glossary.adas.abbr': 'L2+ / L4',
    'glossary.adas.short': 'Poziomy automatyzacji jazdy — od asystenta autostrady po pełną autonomię w strefie.',
    'glossary.adas.def': 'L2+: utrzymanie pasa, adaptacyjny tempomat, hamowanie awaryjne. L4: pełna autonomia w zdefiniowanej domenie. Windrose dostarcza L2+ w standardzie.',
    'glossary.aeb.abbr': 'Autonomiczne hamowanie awaryjne',
    'glossary.aeb.short': 'Automatycznie hamuje przy grożącej kolizji bez reakcji kierowcy.',
    'glossary.aeb.def': 'Radar i kamera przednia śledzą przeszkody. Standard we wszystkich ciężarówkach Windrose.',
    'glossary.avm.abbr': 'Monitor widoku dookoła',
    'glossary.avm.short': '270° widok z lotu ptaka do dokowania i manewrowania.',
    'glossary.avm.def': 'AVM łączy obrazy kamer w perspektywę z góry. 270° pokrycie eliminuje martwe pole przy rampie.',
    'glossary.acc.abbr': 'Adaptacyjny tempomat',
    'glossary.acc.short': 'Automatycznie utrzymuje prędkość i dystans na autostradzie.',
    'glossary.acc.def': 'Utrzymuje z góry ustawiony dystans i integruje hamowanie rekuperacyjne.',
    'glossary.arhud.abbr': 'Head-up display AR',
    'glossary.arhud.short': 'Nawigacja i wskazówki pasa wyświetlane na przedniej szybie.',
    'glossary.arhud.def': 'Strzałki nawigacyjne i ostrzeżenia o zmianie pasa na rzeczywistej drodze. Od Generacji 3.',
    'glossary.cat.regulatory': 'Regulacyjny',
    'glossary.fmvss.abbr': 'Federalne standardy bezpieczeństwa USA',
    'glossary.fmvss.short': 'Federalny kodeks dla każdego pojazdu sprzedawanego w USA.',
    'glossary.fmvss.def': 'FMVSS ustala minimalne wymagania dla hamulców, oświetlenia i ochrony pasażerów. Windrose certyfikowany dla 50 stanów.',
    'glossary.carb.abbr': 'ZEV · ACT · HVIP',
    'glossary.carb.short': 'Nakazy zeroemisyjne Kalifornii i program motywacyjny — najbardziej wpływowe na świecie.',
    'glossary.carb.def': 'CARB ustala najsurowsze przepisy. HVIP: rabaty do $120.000/ciężarówkę. Windrose CARB ZEV/ACT-kwalifikowany i HVIP-uprawniony.',
    'glossary.miit.abbr': 'Chińska homologacja',
    'glossary.miit.short': 'Chiński organ homologacyjny i krajowe normy techniczne.',
    'glossary.miit.def': 'MIIT wydaje homologację dla wszystkich pojazdów w Chinach. Windrose posiada homologację MIIT i zgodność GB/T.',
    'glossary.ecas.abbr': 'Elektroniczne zawieszenie pneumatyczne',
    'glossary.ecas.short': 'Elektronicznie regulowana wysokość jazdy dla ramp i warunków drogowych.',
    'glossary.ecas.def': 'Kierowca podnosi lub opuszcza podwozie. Obniżenie przy rampie eliminuje lukę; autostrada zmniejsza opór powietrza.',
