    'autel_mcs_validation.body.0': 'Windrose and Autel Europe have successfully completed a',
    'autel_mcs_validation.body.1': 'The test confirms interoperability between Windrose trucks and Autel\'s charging infrastructure at commercial power levels.',
    'autel_mcs_validation.headline': 'Windrose and Autel Validate Real-World Megawatt Charging Under MCS Standard',
    'autel_mcs_validation.stat_label.0': 'Charge power',
    'autel_mcs_validation.stat_label.1': 'Standard',
